import{_ as e,o as r,c as i,ah as o}from"./chunks/framework.Bg572dcY.js";const b=JSON.parse('{"title":"RPC 框架","description":"","frontmatter":{"title":"RPC 框架","order":7},"headers":[],"relativePath":"server/network/proto/rpc.md","filePath":"server/network/proto/rpc.md"}'),h={name:"server/network/proto/rpc.md"};function t(l,a,n,c,d,s){return r(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="rpc-框架" tabindex="-1">RPC 框架 <a class="header-anchor" href="#rpc-框架" aria-label="Permalink to “RPC 框架”">​</a></h1><p>RPC（Remote Procedure Call）允许程序像调用本地函数一样调用远程服务，屏蔽网络通信的复杂性。</p><h2 id="rpc-的本质" tabindex="-1">RPC 的本质 <a class="header-anchor" href="#rpc-的本质" aria-label="Permalink to “RPC 的本质”">​</a></h2><p>RPC 的核心思想是将远程调用伪装成本地调用。RPC 框架负责：序列化参数、发起网络请求、等待响应、反序列化结果。</p><h2 id="序列化" tabindex="-1">序列化 <a class="header-anchor" href="#序列化" aria-label="Permalink to “序列化”">​</a></h2><h3 id="文本格式" tabindex="-1">文本格式 <a class="header-anchor" href="#文本格式" aria-label="Permalink to “文本格式”">​</a></h3><p>JSON 是最常见的文本格式，可读性强、支持多种语言。缺点是性能差、体积大。</p><h3 id="二进制格式" tabindex="-1">二进制格式 <a class="header-anchor" href="#二进制格式" aria-label="Permalink to “二进制格式”">​</a></h3><p>Protobuf 是 Google 开发的二进制格式，性能好、体积小、有 Schema。Thrift 是 Facebook 开发的二进制格式。</p><h2 id="rpc-框架组件" tabindex="-1">RPC 框架组件 <a class="header-anchor" href="#rpc-框架组件" aria-label="Permalink to “RPC 框架组件”">​</a></h2><h3 id="客户端" tabindex="-1">客户端 <a class="header-anchor" href="#客户端" aria-label="Permalink to “客户端”">​</a></h3><p>Stub（桩）、序列化器、网络传输、连接池、负载均衡、超时控制、重试机制。</p><h3 id="服务端" tabindex="-1">服务端 <a class="header-anchor" href="#服务端" aria-label="Permalink to “服务端”">​</a></h3><p>网络传输、反序列化器、服务注册、服务实现、线程池、限流控制。</p><h2 id="grpc" tabindex="-1">gRPC <a class="header-anchor" href="#grpc" aria-label="Permalink to “gRPC”">​</a></h2><p>gRPC 是 Google 开源的高性能 RPC 框架，基于 HTTP/2 和 Protobuf。</p><h3 id="http-2-的优势" tabindex="-1">HTTP/2 的优势 <a class="header-anchor" href="#http-2-的优势" aria-label="Permalink to “HTTP/2 的优势”">​</a></h3><p>多路复用、头部压缩、二进制协议、服务端推送。</p><h3 id="grpc-调用模式" tabindex="-1">gRPC 调用模式 <a class="header-anchor" href="#grpc-调用模式" aria-label="Permalink to “gRPC 调用模式”">​</a></h3><p>一元 RPC（Unary）、服务器流 RPC（Server Streaming）、客户端流 RPC（Client Streaming）、双向流 RPC（Bidirectional Streaming）。</p><h2 id="dubbo" tabindex="-1">Dubbo <a class="header-anchor" href="#dubbo" aria-label="Permalink to “Dubbo”">​</a></h2><p>Dubbo 是阿里巴巴开源的高性能 RPC 框架，专注于服务治理。</p><h3 id="dubbo-的架构" tabindex="-1">Dubbo 的架构 <a class="header-anchor" href="#dubbo-的架构" aria-label="Permalink to “Dubbo 的架构”">​</a></h3><p>注册中心（Registry）、协议（Protocol）、负载均衡（Load Balance）、集群容错（Cluster）。</p><h2 id="service-mesh" tabindex="-1">Service Mesh <a class="header-anchor" href="#service-mesh" aria-label="Permalink to “Service Mesh”">​</a></h2><p>Service Mesh 将服务治理从应用代码中剥离，下沉到基础设施层。Sidecar 代理与每个服务实例部署在一起，接管所有进出流量。</p><h3 id="istio" tabindex="-1">Istio <a class="header-anchor" href="#istio" aria-label="Permalink to “Istio”">​</a></h3><p>Istio 是最流行的 Service Mesh 实现，基于 Envoy 代理。</p>',28)])])}const P=e(h,[["render",t]]);export{b as __pageData,P as default};
